// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EmptyTripleSource;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.OptimizationTraceSink;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.Test;

class LegacyGreedyPlannerOrderingTest {

	@Test
	void prefersLowerCardinalityFirstWhenVarsEquivalent() {
		StatementPattern p1 = pattern("http://example.com/p1");
		StatementPattern p2 = pattern("http://example.com/p2");
		StatementPattern p3 = pattern("http://example.com/p3");

		JoinRegion region = new JoinRegion(List.of(p1, p2, p3), List.of(), Set.of(), null);
		JoinEngineConfig config = new JoinEngineConfig(true, 1.5d, 8, 3, true);
		JoinOptimizationContext context = new JoinOptimizationContext(new PredicateCardinalityStats(),
				new EmptyTripleSource(), null, EmptyBindingSet.getInstance(), Set.of(), config,
				OptimizationTraceSink.NOOP, BanditPolicy.noop(), new DefaultUncertaintyAwareEstimator(),
				new DefaultCostModel());

		LegacyGreedyPlanner planner = new LegacyGreedyPlanner();
		List<JoinOrderCandidate> candidates = planner.generatePlans(region, context);

		assertThat(candidates).hasSize(1);
		List<String> order = predicates(candidates.get(0).getOrderIndices(), region.getAtoms());
		assertThat(order).startsWith("http://example.com/p2");
		assertThat(order).containsExactlyInAnyOrder("http://example.com/p1", "http://example.com/p2",
				"http://example.com/p3");
	}

	private static StatementPattern pattern(String predicate) {
		return new StatementPattern(new Var("s"),
				new Var("p", SimpleValueFactory.getInstance().createIRI(predicate)),
				new Var("o"));
	}

	private static List<String> predicates(List<Integer> orderIndices, List<TupleExpr> baseOrder) {
		return orderIndices.stream()
				.map(baseOrder::get)
				.map(StatementPattern.class::cast)
				.map(sp -> sp.getPredicateVar().getValue().stringValue())
				.toList();
	}

	private static final class PredicateCardinalityStats extends EvaluationStatistics {

		private final IRI p1 = iri("http://example.com/p1");
		private final IRI p2 = iri("http://example.com/p2");
		private final IRI p3 = iri("http://example.com/p3");

		@Override
		public double getCardinality(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				StatementPattern pattern = (StatementPattern) expr;
				if (pattern.getPredicateVar() != null && pattern.getPredicateVar().hasValue()) {
					IRI predicate = (IRI) pattern.getPredicateVar().getValue();
					if (p1.equals(predicate)) {
						return 500.0d;
					}
					if (p2.equals(predicate)) {
						return 1.0d;
					}
					if (p3.equals(predicate)) {
						return 2.0d;
					}
				}
			}
			return super.getCardinality(expr);
		}

		private static IRI iri(String value) {
			return SimpleValueFactory.getInstance().createIRI(value);
		}
	}
}
